# Scan the extracted codebase for where "emergent events" are created/reported
from pathlib import Path
import re, json

root = Path("/mnt/data/parallax_runtime_extract")

hits = []
for p in root.rglob("*.py"):
    text = p.read_text(encoding="utf-8", errors="ignore")
    for i, line in enumerate(text.splitlines(), 1):
        if re.search(r"\bemergent\b", line, re.I) or re.search(r"\bevent[s]?\b", line, re.I):
            # capture likely logging/print/report lines
            if ("print(" in line) or ("logger." in line) or ("log." in line) or ("report" in line.lower()) or ("emit" in line.lower()):
                hits.append({"file": str(p.relative_to(root)), "line": i, "code": line.strip()})
                
len(hits), hits[:25]

# Quick static analysis: identify loops that may print emergent events unthrottled
import ast, textwrap

flood_candidates = []

for p in root.rglob("*.py"):
    src = p.read_text(encoding="utf-8", errors="ignore")
    try:
        tree = ast.parse(src)
    except Exception:
        continue
    # Detect prints inside loops without guards
    class LoopPrintFinder(ast.NodeVisitor):
        def __init__(self):
            self.finds = []
            self.loop_depth = 0
        def visit_For(self, node):
            self.loop_depth += 1
            self.generic_visit(node)
            self.loop_depth -= 1
        def visit_While(self, node):
            self.loop_depth += 1
            self.generic_visit(node)
            self.loop_depth -= 1
        def visit_Call(self, node):
            if isinstance(node.func, ast.Name) and node.func.id == "print" and self.loop_depth>0:
                self.finds.append((node.lineno, ast.get_source_segment(src, node) or "print(...)"))
            self.generic_visit(node)
    v = LoopPrintFinder()
    v.visit(tree)
    if v.finds:
        flood_candidates.append({"file": str(p.relative_to(root)), "prints_in_loops": v.finds[:20]})
        
flood_candidates[:5], len(flood_candidates)
